curl -s -X POST "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal" \
  -H "Content-Type: application/json" \
  -d '{
    "app_id": "cli_a9f25697be389ceb",
    "app_secret": "caJHD9D8Wiw5NvxHmrAUbbpUurctZfEs"
  }' | head -c 200

# 重新获取token
NEW_TOKEN=$(curl -s -X POST "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal" \
  -H "Content-Type: application/json" \
  -d '{
    "app_id": "cli_a9f25697be389ceb",
    "app_secret": "caJHD9D8Wiw5NvxHmrAUbbpUurctZfEs"
  }' | grep -o '"tenant_access_token":"[^"]*"' | cut -d'"' -f4)

echo "新Token: ${NEW_TOKEN:0:20}..."

# 查看表格字段
curl -s -X GET "https://open.feishu.cn/open-apis/bitable/v1/apps/FCRNbSo4ja4hCEs5411cNZQXnkh/tables/tblRmMB6LIdLHyEt/fields" \
  -H "Authorization: Bearer $NEW_TOKEN" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    if 'data' in data and 'items' in data['data']:
        print('表格字段结构:')
        for field in data['data']['items']:
            print(f'  {field[\"field_name\"]}: {field[\"type\"]}')
    else:
        print('无法获取字段结构:', data.get('msg', '未知错误'))
except:
    print('解析失败')
" 2>/dev/null || echo "需要Python解析"

